commands.command:
python -c "import ast,pathlib,sys; ok=True
for p in pathlib.Path('apps').rglob('services/*.py'):
    t=ast.parse(p.read_text())
    for n in ast.walk(t):
        if isinstance(n,(ast.FunctionDef,ast.AsyncFunctionDef)):
            writes=sum(1 for x in ast.walk(n) if isinstance(x,ast.Attribute) and x.attr in {'create','save','update','delete','bulk_create','bulk_update'})
            atomic=any('atomic' in ast.unparse(d) for d in n.decorator_list)
            if writes>=2 and not atomic:
                print(f'{p}:{n.lineno}:{n.name} has {writes} writes, no @transaction.atomic'); ok=False
sys.exit(0 if ok else 1)"

