# utils/pricing.py — pure function, no DB, no side effects from decimal import Decimal
def calculate_discount(subtotal, discount_percent, *, max_discount=None): """Calculate discount amount from subtotal and percentage.""" discount = subtotal * Decimal(discount_percent) / 100 if max_discount is not None: discount = min(discount, max_discount) return discount.quantize(Decimal('0.01'))
# Test: trivial assert calculate_discount(Decimal('100'), 10) == Decimal('10.00') assert calculate_discount(Decimal('100'), 50, max_discount=Decimal('10')) == Decimal('10.00')
